INSERT INTO `products` VALUES (1,1,'SOLVIK Sofa','Modern 3-seater sofa in premium grey fabric with solid oak legs. Perfect for contemporary living spaces.',899.00,8,'https://storage.googleapis.com/ekea-image-bucket/solvik_sofa.jpg','2026-03-02 13:19:57'),(2,1,'BJÖRK Coffee Table','Minimalist round coffee table in natural birch veneer with powder-coated steel legs.',249.00,16,'https://storage.googleapis.com/ekea-image-bucket/bjork_coffee.jpg','2026-03-02 13:19:57'),(3,1,'STRÖM TV Console','Sleek TV bench in walnut finish with cable management and two drawers.',399.00,6,'https://storage.googleapis.com/ekea-image-bucket/strom_tv.jpg','2026-03-02 13:19:57'),(4,2,'NORRA Bed Frame','King-size bed frame in solid pine with slatted base. Clean Scandinavian design.',649.00,0,'https://storage.googleapis.com/ekea-image-bucket/norra_bed.jpg','2026-03-02 13:19:57'),(6,2,'LUGN Bedside Table','Compact bedside table with one drawer and open shelf. Available in oak finish.',129.00,3,'https://storage.googleapis.com/ekea-image-bucket/lugn_bedside.jpg','2026-03-02 13:19:57'),(7,3,'VILA Dining Table','Extendable dining table seating 4-8 in solid oak. Built for family gatherings.',599.00,8,'https://storage.googleapis.com/ekea-image-bucket/vila_dining.jpg','2026-03-02 13:19:57'),(8,3,'SKÅL Dining Chair','Ergonomic dining chair in moulded beech plywood with felt-padded feet.',89.00,4,'https://storage.googleapis.com/ekea-image-bucket/skal_chair.jpg','2026-03-02 13:19:57'),(9,4,'TANKE Standing Desk','Height-adjustable standing desk with bamboo top and motorised legs.',749.00,3,'https://storage.googleapis.com/ekea-image-bucket/tanke_desk.jpg','2026-03-02 13:19:57'),(10,4,'FOKUS Office Chair','Ergonomic mesh office chair with lumbar support and adjustable armrests.',449.00,4,'https://storage.googleapis.com/ekea-image-bucket/fokus_chair.jpg','2026-03-02 13:19:57'),(11,4,'HYLLA Bookshelf','Open 5-tier bookshelf in powder-coated black steel with oak shelves.',299.00,98,'https://storage.googleapis.com/ekea-image-bucket/hylla_bookshelf.jpg','2026-03-02 13:19:57'),(12,5,'ORDNA Storage Cabinet','Tall storage cabinet with 4 doors and internal adjustable shelves. White finish.',349.00,2,'https://storage.googleapis.com/ekea-image-bucket/ordna_cabinet.jpg','2026-03-02 13:19:57'),(13,5,'PLATS Shelving Unit','Modular wall-mounted shelving system in natural pine. Customisable layout.',199.00,0,'https://storage.googleapis.com/ekea-image-bucket/plats_shelving.jpg','2026-03-02 13:19:57'),(14,5,'RENSA Organisers Set','Set of 6 fabric storage boxes in assorted neutral colours. Fits most shelving units.',49.00,20,'https://storage.googleapis.com/ekea-image-bucket/rensa_organisers.jpg','2026-03-02 13:19:57');
/*!40000 ALTER TABLE `products` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `reviews`
--

DROP TABLE IF EXISTS `reviews`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reviews` (
  `id` int NOT NULL AUTO_INCREMENT,
  `user_id` int unsigned NOT NULL,
  `product_id` int NOT NULL,
  `rating` tinyint NOT NULL,
  `comment` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `user_id` (`user_id`),
  KEY `product_id` (`product_id`),
  CONSTRAINT `reviews_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `reviews_ibfk_2` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `reviews_chk_1` CHECK ((`rating` between 1 and 5))
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

