INSERT INTO `reviews` VALUES (4,3,2,5,'I LOVE THIS!','2026-03-31 19:42:37'),(6,5,6,5,'Very good!','2026-04-01 07:42:14'),(7,13,13,4,'wood quality is solid, real wood, fits perfectly in my house. :D\r\n\r\nBUT delivery takes too long! :(','2026-04-03 05:39:35');
